import logging
import json
import hmac
import hashlib
import azure.functions as func
from datetime import datetime

# Configuration
PAYMENT_PROVIDERS = {
    'stripe': 'stripe_signature',
    'paypal': 'paypal_payment_id',
    'square': 'square_signature'
}

def verify_signature(request_body, signature, provider, secret):
    """Verify webhook signature for security"""
    if provider == 'stripe':
        # Stripe signature verification
        if not signature.startswith('t='):
            return False
        timestamp = signature.split(',')[0].split('=')[1]
        sig = signature.split(',')[1].split('=')[1]
        
        # Verify timestamp (prevent replay attacks)
        if abs(datetime.now().timestamp() - int(timestamp)) > 300:  # 5 minutes
            return False
            
        # Verify signature
        expected_sig = hmac.new(
            secret.encode('utf-8'),
            f"{timestamp}.{request_body}".encode('utf-8'),
            hashlib.sha256
        ).hexdigest()
        
        return hmac.compare_digest(sig, expected_sig)
    
    elif provider == 'paypal':
        # PayPal signature verification
        return hmac.compare_digest(
            hmac.new(
                secret.encode('utf-8'),
                request_body.encode('utf-8'),
                hashlib.sha256
            ).hexdigest(),
            signature
        )
    
    return False

def process_payment_notification(payment_data):
    """Process payment notification data"""
    try:
        # Validate required fields
        required_fields = ['payment_id', 'amount', 'status', 'provider']
        for field in required_fields:
            if field not in payment_data:
                raise ValueError(f"Missing required field: {field}")
        
        # Validate amount
        if not isinstance(payment_data['amount'], (int, float)) or payment_data['amount'] <= 0:
            raise ValueError("Invalid amount")
        
        # Validate status
        valid_statuses = ['completed', 'failed', 'pending', 'refunded']
        if payment_data['status'] not in valid_statuses:
            raise ValueError(f"Invalid status: {payment_data['status']}")
        
        # Process payment logic here
        logging.info(f"Processing payment: {payment_data['payment_id']}")
        
        # Return success response
        return {
            'status': 'success',
            'message': 'Payment processed successfully',
            'payment_id': payment_data['payment_id']
        }
        
    except Exception as e:
        logging.error(f"Error processing payment: {str(e)}")
        raise

def main(req: func.HttpRequest) -> func.HttpResponse:
    """Main webhook function"""
    try:
        # Log incoming request
        logging.info(f"Webhook received from {req.url}")
        
        # Get provider from headers
        provider = req.headers.get('X-Provider')
        if not provider:
            provider = req.headers.get('X-Payment-Provider')
        
        if not provider or provider not in PAYMENT_PROVIDERS:
            return func.HttpResponse(
                json.dumps({'error': 'Invalid or missing provider'}),
                status_code=400,
                mimetype='application/json'
            )
        
        # Get signature
        signature = req.headers.get('X-Signature') or req.headers.get('Authorization')
        if not signature:
            return func.HttpResponse(
                json.dumps({'error': 'Missing signature'}),
                status_code=401,
                mimetype='application/json'
            )
        
        # Get request body
        try:
            request_body = req.get_body().decode('utf-8')
        except Exception as e:
            logging.error(f"Error reading request body: {str(e)}")
            return func.HttpResponse(
                json.dumps({'error': 'Invalid request body'}),
                status_code=400,
                mimetype='application/json'
            )
        
        # Get secret key (in production, use Azure Key Vault)
        secret = req.headers.get('X-Secret-Key') or 'default_secret_key'
        
        # Verify signature
        if not verify_signature(request_body, signature, provider, secret):
            return func.HttpResponse(
                json.dumps({'error': 'Invalid signature'}),
                status_code=401,
                mimetype='application/json'
            )
        
        # Parse JSON data
        try:
            payment_data = json.loads(request_body)
        except json.JSONDecodeError:
            return func.HttpResponse(
                json.dumps({'error': 'Invalid JSON data'}),
                status_code=400,
                mimetype='application/json'
            )
        
        # Process payment
        result = process_payment_notification(payment_data)
        
        return func.HttpResponse(
            json.dumps(result),
            status_code=200,
            mimetype='application/json'
        )
        
    except Exception as e:
        logging.error(f"Webhook processing error: {str(e)}")
        return func.HttpResponse(
            json.dumps({'error': 'Internal server error'}),
            status_code=500,
            mimetype='application/json'
        )